const perfData = $('Get Performance Card').first().json;

const prompt = `Generate a Twitter thread (4-6 tweets) reviewing this week's BTC Seer performance. Here's the data:

${JSON.stringify(perfData, null, 2)}

Tweet 1: hook/headline that grabs attention.
Tweet 2-3: specific data points and stats.
Tweet 4: insight or lesson learned this week.
Last tweet: CTA to try @BTC_Seer_Bot on Telegram.

Each tweet max 270 chars. Include #Bitcoin #BTC in at least the first and last tweets.
Return ONLY a JSON array of strings, e.g. ["tweet1", "tweet2", ...]. No other text.`;

return [{ json: { prompt } }];

const response = $('Claude Generate Thread').first().json;
const rawText = response.content[0].text.trim();

let tweets;
try {
  tweets = JSON.parse(rawText);
} catch (e) {
  // Try to extract JSON array from response
  const match = rawText.match(/\[.*\]/s);
  if (match) {
    tweets = JSON.parse(match[0]);
  } else {
    tweets = [rawText.substring(0, 270)];
  }
}

// Return each tweet as a separate item for SplitInBatches
return tweets.map((tweet, index) => ({
  json: { text: tweet, threadIndex: index, isFirst: index === 0 }
}));

